__kernel void dynproc_kernel(
    const int pyramid_height,
    __global const int* wall,
    __global int* src,
    __global int* dst,
    const int cols,
    const int rows,
    const int t,
    const int borderCols,
    const int theHalo,
    __local int* localSrc1,
    __local int* localSrc2,
    __global int* outputBuffer)
{
    int n = get_global_id(0);
    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Each work-item processes one column index n
    // We process pyramid_height steps in this kernel invocation

    // Load initial src values into local memory for halo access
    // We need to load src[n] and neighbors for min calculation

    // For each step in pyramid_height
    // We update dst[n] based on src and wall

    // Because the original code swaps src and dst each iteration,
    // here we simulate that by ping-ponging local buffers

    // We assume wall is linearized as wall[row * cols + col]

    // Initialize local buffers for ping-pong
    // localSrc1 and localSrc2 are local memory arrays of size local_size

    // We will process pyramid_height steps or until rows exhausted

    // Compute global index for wall access
    int col = n;
    int row = t;

    // Bounds check
    if (col >= cols)
        return;

    // Load initial src values into localSrc1
    // src corresponds to wall[t][n] + min of neighbors from previous step
    // But initial src is passed in as src array

    // For the first step, src is input; for subsequent steps, we use local buffers

    // Load src[n] into localSrc1
    localSrc1[local_id] = src[col];
    barrier(CLK_LOCAL_MEM_FENCE);

    // Process pyramid_height steps or until rows exhausted
    for (int step = 0; step < pyramid_height && (row + step + 1) < rows; step++) {
        // Compute min of src[n], src[n-1], src[n+1]
        int min_val = localSrc1[local_id];
        if (col > 0)
            min_val = min(min_val, localSrc1[local_id - 1]);
        if (col < cols - 1)
            min_val = min(min_val, localSrc1[local_id + 1]);

        // Compute dst value
        int wall_val = wall[(row + step + 1) * cols + col];
        int dst_val = wall_val + min_val;

        // Store dst_val in localSrc2
        localSrc2[local_id] = dst_val;

        barrier(CLK_LOCAL_MEM_FENCE);

        // Swap localSrc1 and localSrc2 pointers for next iteration
        __local int* temp = localSrc1;
        localSrc1 = localSrc2;
        localSrc2 = temp;
    }

    // After pyramid_height steps, write final result to dst global memory
    dst[col] = localSrc1[local_id];
}
